13	// DefaultPreClaimTimeout bounds pre-claim readiness hooks when callers do not
14	// provide an explicit timeout.
15	const DefaultPreClaimTimeout = 5 * time.Minute
16	
17	const SystemicPreClaimReasonPrefix = "systemic_preclaim:"
18	
19	// TrackerContentionPreClaimReasonPrefix marks a pre-claim skip caused by
20	// transient multi-worker contention on DDx-managed tracker/metadata files
21	// (.ddx/beads.jsonl, .ddx/metrics/attempts.jsonl, …) rather than a systemic
22	// repo-config problem. Like systemic skips it idles without cooldowning the
23	// bead, but it carries a distinct reason code so operators can tell transient
24	// contention apart from a configuration wedge (ddx-df77e668).
25	const TrackerContentionPreClaimReasonPrefix = "tracker_contention_preclaim:"
26	
27	// preClaimClass categorizes a pre-claim hook error so the guard can choose
28	// between idling without cooldown (systemic / tracker-contention) and the
29	// per-bead two-strikes cooldown policy (bead-specific failures).
30	type preClaimClass int
31	
32	const (
33		preClaimClassBeadSpecific preClaimClass = iota
34		preClaimClassSystemic
35		preClaimClassTrackerContention
36	)
37	
38	// trackerMetadataPaths are the DDx-managed metadata files that concurrent
39	// workers rewrite continuously. They are append-mostly metadata, not code, so
40	// a staged-changes pre-claim error that mentions only these paths is transient
41	// multi-worker contention — not a systemic repo-config problem (ddx-df77e668).
42	// Kept in sync with agent.durableAuditManagedPathspecs; duplicated here because
43	// the agent package imports this one, so the dependency cannot run the other
44	// way.
45	var trackerMetadataPaths = []string{
46		".ddx/beads.jsonl",
47		".ddx/beads-archive.jsonl",
48		".ddx/metrics/attempts.jsonl",
49		".ddx/attachments",
50	}
