52	// Guard decides whether a bead may proceed. Callers use the returned reason
53	// for skip telemetry and logs.
54	type Guard interface {
55		Allow(ctx context.Context, beadID string) (bool, string)
56	}
57	
58	// cooldownStore is the minimal store surface PreClaimGuard needs.
59	type cooldownStore interface {
60		SetExecutionCooldown(id string, until time.Time, status, detail, baseRev string) error
61	}
62	
63	// PreClaimHook matches the work pre-claim hook signature.
64	type PreClaimHook func(ctx context.Context) error
65	
66	// PreClaimGuard implements the two-strikes pre-claim policy. The first hook
67	// failure skips the candidate and retries it on the next presentation; the
68	// second failure parks the bead on execution cooldown.
69	type PreClaimGuard struct {
70		hook     PreClaimHook
71		store    cooldownStore
72		log      io.Writer
73		now      func() time.Time
74		cooldown time.Duration
75		timeout  time.Duration
76	
77		mu             sync.Mutex
78		failCounts     map[string]int
79		loggedSystemic map[string]bool
80	}
81	
82	// NewPreClaimGuard constructs a Guard that owns the pre-claim hook retry
83	// state for one worker run.
84	func NewPreClaimGuard(hook PreClaimHook, store cooldownStore, log io.Writer, now func() time.Time, cooldown, timeout time.Duration) *PreClaimGuard {
85		if now == nil {
86			now = time.Now
87		}
88		if cooldown <= 0 {
89			cooldown = 30 * time.Second
90		}
91		if timeout <= 0 {
92			timeout = DefaultPreClaimTimeout
93		}
94		return &PreClaimGuard{
95			hook:           hook,
96			store:          store,
97			log:            log,
98			now:            now,
99			cooldown:       cooldown,
100			timeout:        timeout,
101			failCounts:     make(map[string]int),
102			loggedSystemic: make(map[string]bool),
103		}
104	}
105	
106	// Allow runs the pre-claim hook and applies the two-strikes retry policy.
107	func (g *PreClaimGuard) Allow(ctx context.Context, beadID string) (bool, string) {
108		if g == nil || g.hook == nil {
109			return true, ""
110		}
111		err, timedOut := callPreClaimHookWithTimeout(ctx, g.hook, g.timeout)
112		if err != nil || timedOut {
113			switch classifyPreClaimError(err) {
114			case preClaimClassTrackerContention:
115				reason := err.Error()
116				g.mu.Lock()
117				shouldLog := !g.loggedSystemic[reason]
118				g.loggedSystemic[reason] = true
119				g.mu.Unlock()
120				if shouldLog && g.log != nil {
121					_, _ = fmt.Fprintf(g.log, "pre-claim hook: %v (transient tracker-file contention; leaving beads untouched)\n", err)
122				}
123				return false, TrackerContentionPreClaimReasonPrefix + reason
124			case preClaimClassSystemic:
125				reason := err.Error()
126				g.mu.Lock()
127				shouldLog := !g.loggedSystemic[reason]
128				g.loggedSystemic[reason] = true
129				g.mu.Unlock()
130				if shouldLog && g.log != nil {
131					_, _ = fmt.Fprintf(g.log, "pre-claim hook: %v (systemic; leaving beads untouched)\n", err)
132				}
133				return false, SystemicPreClaimReasonPrefix + reason
134			}
135	
136			g.mu.Lock()
137			defer g.mu.Unlock()
138	
139			g.failCounts[beadID]++
140			if g.failCounts[beadID] >= 2 {
141				if g.store != nil {
142					until := g.now().UTC().Add(g.cooldown)
143					detail := "pre-claim hook failed"
144					if err != nil {
145						detail = err.Error()
146					} else if timedOut {
147						detail = fmt.Sprintf("pre-claim hook timed out after %s", g.timeout)
148					}
149					_ = g.store.SetExecutionCooldown(beadID, until, "preclaim-hook-failed", detail, "")
150				}
151			}
152			if g.log != nil {
153				switch {
154				case timedOut:
155					_, _ = fmt.Fprintf(g.log, "pre-claim hook timed out after %s (skipping %s)\n", g.timeout, beadID)
156				case err != nil:
157					_, _ = fmt.Fprintf(g.log, "pre-claim hook: %v (skipping %s)\n", err, beadID)
158				}
159			}
160			if timedOut {
161				return false, fmt.Sprintf("pre-claim hook timed out after %s", g.timeout)
162			}
163			return false, err.Error()
164		}
165	
166		g.mu.Lock()
167		delete(g.failCounts, beadID)
168		g.mu.Unlock()
169		return true, ""
170	}
