230	// isStagedTrackerContentionError reports whether a "landing worktree has staged
231	// changes" error lists only DDx-managed tracker/metadata files. A mixed or
232	// code-only staged set is NOT tracker contention (it is systemic).
233	func isStagedTrackerContentionError(msg string) bool {
234		if !strings.Contains(msg, "staged changes after waiting") {
235			return false
236		}
237		paths := stagedPathsFromError(msg)
238		if len(paths) == 0 {
239			return false
240		}
241		for _, p := range paths {
242			if !isTrackerMetadataPath(p) {
243				return false
244			}
245		}
246		return true
247	}
248	
249	// stagedPathsFromError extracts the repo-relative paths from the
250	// "landing worktree has staged changes after waiting <d>:\n<status>\t<path>"
251	// error body. Each path line is "<status><TAB><path>" (git diff --name-status);
252	// the leading summary line (before the first newline) is skipped.
253	func stagedPathsFromError(msg string) []string {
254		lines := strings.Split(msg, "\n")
255		if len(lines) <= 1 {
256			return nil
257		}
258		var paths []string
259		for _, line := range lines[1:] {
260			line = strings.TrimSpace(line)
261			if line == "" {
262				continue
263			}
264			if tab := strings.IndexByte(line, '\t'); tab >= 0 {
265				line = line[tab+1:]
266			}
267			line = strings.TrimSpace(line)
268			if line != "" {
269				paths = append(paths, line)
270			}
271		}
272		return paths
273	}
