291	type preClaimHookCallResult struct {
292		err error
293	}
294	
295	func callPreClaimHookWithTimeout(ctx context.Context, hook PreClaimHook, timeout time.Duration) (error, bool) {
296		if hook == nil {
297			return nil, false
298		}
299		if timeout <= 0 {
300			timeout = DefaultPreClaimTimeout
301		}
302		hookCtx, cancel := context.WithTimeout(ctx, timeout)
303		defer cancel()
304	
305		resultCh := make(chan preClaimHookCallResult, 1)
306		go func() {
307			resultCh <- preClaimHookCallResult{err: hook(hookCtx)}
308		}()
309	
310		select {
311		case result := <-resultCh:
312			if errors.Is(hookCtx.Err(), context.DeadlineExceeded) || errors.Is(result.err, context.DeadlineExceeded) {
313				return context.DeadlineExceeded, true
314			}
315			return result.err, false
316		case <-hookCtx.Done():
317			if errors.Is(hookCtx.Err(), context.DeadlineExceeded) {
318				return context.DeadlineExceeded, true
319			}
320			return hookCtx.Err(), false
321		}
322	}
