324	// ComplexityGuard is a compatibility wrapper that delegates to a configured
325	// bead readiness gate. When no gate is configured it allows the bead to
326	// proceed. The model-backed readiness hook is now the canonical pre-claim
327	// gate; this wrapper remains only for callers that still inject a Guard directly.
328	type ComplexityGuard struct {
329		Gate Guard
330		Log  io.Writer
331	
332		once sync.Once
333	}
