340	// Allow either delegates to the configured gate or fail-opens silently when the
341	// gate is absent.
342	func (g *ComplexityGuard) Allow(ctx context.Context, beadID string) (bool, string) {
343		if g == nil || g.Gate == nil {
344			return true, ""
345		}
346		return g.Gate.Allow(ctx, beadID)
347	}
