576	func isRecoverableLandingIndexCorruption(output string) bool {
577		lower := strings.ToLower(output)
578		return strings.Contains(lower, "index file smaller than expected") ||
579			strings.Contains(lower, "bad index file") ||
580			strings.Contains(lower, "unexpected end of file while reading index")
581	}
