583	// blockingStagedPaths returns the staged paths that would genuinely block a
584	// claim — i.e. every staged path that is NOT a DDx-managed tracker/metadata
585	// file. ok is false when the staged list cannot be read (e.g. a corrupt
586	// index), so callers can fall through to their corruption-recovery path
587	// instead of mistaking the read failure for "no blocking changes".
588	func blockingStagedPaths(dir string) (blocking []string, ok bool) {
589		out, err := internalgit.Command(context.Background(), dir, "diff", "--cached", "--name-only").CombinedOutput()
590		if err != nil {
591			return nil, false
592		}
593		for _, line := range strings.Split(strings.TrimSpace(string(out)), "\n") {
594			p := strings.TrimSpace(line)
595			if p == "" || isDDxManagedTrackerPath(p) {
596				continue
597			}
598			blocking = append(blocking, p)
599		}

590		if err != nil {
591			return nil, false
592		}
593		for _, line := range strings.Split(strings.TrimSpace(string(out)), "\n") {
594			p := strings.TrimSpace(line)
595			if p == "" || isDDxManagedTrackerPath(p) {
596				continue
597			}
598			blocking = append(blocking, p)
