603	// isDDxManagedTrackerPath reports whether a repo-relative path is one of the
604	// DDx-managed tracker/metadata files that workers rewrite continuously
605	// (.ddx/beads.jsonl, .ddx/metrics/attempts.jsonl, .ddx/attachments/, …). These
606	// are append-mostly metadata, not code, so they must not block pre-claim
607	// (ddx-df77e668). The managed set is the same one durable-audit commits own.
608	func isDDxManagedTrackerPath(path string) bool {
609		clean := strings.TrimSpace(filepath.ToSlash(path))
610		if clean == "" {
611			return false
612		}
613		for _, managed := range durableAuditManagedPathspecs {
614			m := strings.TrimSuffix(filepath.ToSlash(managed), "/")
615			if clean == m || strings.HasPrefix(clean, m+"/") {
616				return true
617			}
618		}
619		return false
620	}
