622	// indexMatchesRecentAncestorTree reports whether the current index's tree
623	// matches the tree of any of the last `maxDepth` ancestors of HEAD. A
624	// match means the index reflects a state we have already advanced past —
625	// the signature of a swallowed SyncWorkTreeToHead failure — and is
626	// therefore safe to overwrite by re-reading HEAD into the index.
627	//
628	// Operator-staged work introduces novel tree contents that will not
629	// match any historical tree, so the heuristic preserves their work.
630	func indexMatchesRecentAncestorTree(dir string, maxDepth int) (bool, error) {
631		out, err := internalgit.Command(context.Background(), dir, "write-tree").Output()
632		if err != nil {
633			return false, err
634		}
635		indexTree := strings.TrimSpace(string(out))
636		if indexTree == "" {
637			return false, nil
638		}
639		for depth := 1; depth <= maxDepth; depth++ {
640			ref := fmt.Sprintf("HEAD~%d^{tree}", depth)
641			treeOut, treeErr := internalgit.Command(context.Background(), dir, "rev-parse", "--verify", ref).Output()
642			if treeErr != nil {
643				return false, nil
644			}
645			if strings.TrimSpace(string(treeOut)) == indexTree {
646				return true, nil
647			}
648		}
649		return false, nil
650	}
