652	func checkoutSyncDirtyOverlapPaths(dir, fromRev string, dirtyPaths []string) ([]string, error) {
653		if fromRev == "" || len(dirtyPaths) == 0 {
654			return nil, nil
655		}
656		diffOut, diffErr := internalgit.Command(context.Background(), dir, "diff", "--name-only", fromRev, "HEAD").CombinedOutput()
657		if diffErr != nil {
658			return nil, diffErr
659		}
660		changed := map[string]bool{}
661		for _, path := range strings.Fields(strings.TrimSpace(string(diffOut))) {
662			changed[filepath.ToSlash(path)] = true
663		}
664		if len(changed) == 0 {
665			return nil, nil
666		}
667		var overlap []string
668		for _, path := range dirtyPaths {
669			slashPath := filepath.ToSlash(path)
670			if checkoutSyncDeferralIgnoredPath(slashPath) {
671				continue
672			}
673			if changed[slashPath] {
674				overlap = append(overlap, slashPath)
675			}
676		}
677		return overlap, nil
678	}
