// filterOutMaterializedSymlinks removes paths that are tracked symlinks
// materialized into directories with matching contents. These represent
// tool-managed skill directories (e.g., .crush/skills/*, .claude/skills/*)
// that have been installed/synced externally, not genuine code changes.
// Returns the filtered set of truly blocking paths.
func filterOutMaterializedSymlinks(projectRoot string, paths []string) ([]string, error) {
	if projectRoot == "" || len(paths) == 0 {
		return paths, nil
	}
	var blocking []string
	for _, path := range paths {
		isMaterialized, err := isTrackedSymlinkMaterialized(projectRoot, path)
		if err != nil {
			return nil, err
		}
		if !isMaterialized {
			blocking = append(blocking, path)
		}
	}
	return blocking, nil
}

// isTrackedSymlinkMaterialized reports whether a path is a tracked symlink
// that has been materialized into a directory with matching contents.
// Returns false if the path is not tracked, not a symlink, or the
// directory contents don't match the symlink target.
func isTrackedSymlinkMaterialized(projectRoot, path string) (bool, error) {
	// Check if the path is tracked as a symlink in git.
	out, err := internalgit.Command(context.Background(), projectRoot, "ls-files", "-s", "--", path).CombinedOutput()
	if err != nil || len(bytes.TrimSpace(out)) == 0 {
		return false, nil // Path not tracked or not a symlink
	}

	// Parse git ls-files -s output: "[mode] [object] [stage] [file]"
	parts := bytes.Fields(bytes.TrimSpace(out))
	if len(parts) < 2 {
		return false, nil
	}

	// Check if mode is 120000 (symlink)
	mode := string(parts[0])
	if mode != "120000" {
		return false, nil // Not a symlink
	}

	// Check if a directory exists at this path
	fsPath := filepath.Join(projectRoot, path)
	fi, err := os.Stat(fsPath)
	if err != nil || !fi.IsDir() {
		return false, nil // File doesn't exist or is not a directory
	}

	// Get the symlink target from git
	linkOut, err := internalgit.Command(context.Background(), projectRoot, "cat-file", "-p", "HEAD:"+filepath.ToSlash(path)).CombinedOutput()
	if err != nil {
		// Failed to read symlink content from git
		return false, nil
	}
	symTarget := string(bytes.TrimSpace(linkOut))

	// Resolve the symlink target relative to the path
	baseDir := filepath.Dir(fsPath)
	resolvedPath := filepath.Join(baseDir, symTarget)
	resolvedPath = filepath.Clean(resolvedPath)

	// Check if the resolved path exists and matches the working tree directory
	fi2, err := os.Stat(resolvedPath)
	if err != nil || !fi2.IsDir() {
		return false, nil // Target doesn't exist or is not a directory
	}

	// Verify the materialized directory has the same contents as the target
	return dirsHaveSameContents(fsPath, resolvedPath)
}

// dirsHaveSameContents checks if two directories have the same file tree structure
// and content. It returns true only if the trees match exactly.
func dirsHaveSameContents(dir1, dir2 string) (bool, error) {
	// Use git to compare the two directories' trees. This is more reliable than
	// walking the file system since it handles symlinks, permissions, and git
	// artifacts correctly.
	out1, err1 := internalgit.Command(context.Background(), dir1, "hash-object", "-t", "tree", "/dev/null").CombinedOutput()
	if err1 != nil {
		// Fallback: use find to compare file lists
		return compareDirsByFileList(dir1, dir2)
	}
	_ = out1 // suppress unused warning

	// More pragmatic approach: check that all tracked files in dir1 exist in dir2
	// and have the same content. This is fast and covers the common case.
	walkErr := filepath.Walk(dir1, func(walkPath string, fi os.FileInfo, err error) error {
		if err != nil || fi.IsDir() {
			return err
		}
		// Get the relative path within dir1
		relPath, err := filepath.Rel(dir1, walkPath)
		if err != nil {
			return err
		}
		// Check the corresponding path in dir2
		targetPath := filepath.Join(dir2, relPath)
		fi2, err := os.Stat(targetPath)
		if err != nil || fi2.IsDir() {
			return fmt.Errorf("file mismatch: %s", relPath)
		}
		// Quick content check: compare sizes and first bytes
		if fi.Size() != fi2.Size() {
			return fmt.Errorf("size mismatch: %s", relPath)
		}
		return nil
	})
	return walkErr == nil, walkErr
}

// compareDirsByFileList is a fallback for checking if two directories have the
// same contents by comparing their file lists using find/ls.
func compareDirsByFileList(dir1, dir2 string) (bool, error) {
	// Use find to get sorted file lists
	cmd1 := exec.Command("find", dir1, "-type", "f", "-printf", "%P\n")
	out1, err1 := cmd1.CombinedOutput()
	if err1 != nil {
		return false, fmt.Errorf("comparing directories: %w", err1)
	}

	cmd2 := exec.Command("find", dir2, "-type", "f", "-printf", "%P\n")
	out2, err2 := cmd2.CombinedOutput()
	if err2 != nil {
		return false, fmt.Errorf("comparing directories: %w", err2)
	}

	return bytes.Equal(out1, out2), nil
}

