package agent

import (
	"bytes"
	"fmt"
	"os"
	"path/filepath"
	"testing"

	internalgit "github.com/DocumentDrivenDX/ddx/internal/git"
)

// TestPreClaim_MaterializedSkillSymlinkIsNotImplementationDirt verifies that
// when a tracked symlink (e.g., .crush/skills/nano-banana-pro-openrouter) is
// materialized into a directory with matching contents, the pre-claim
// cleanliness check does NOT classify it as uncommitted implementation
// changes and the drain continues.
func TestPreClaim_MaterializedSkillSymlinkIsNotImplementationDirt(t *testing.T) {
	// Create a temporary repo with a tracked symlink
	tempDir := t.TempDir()
	repoDir := filepath.Join(tempDir, "repo")
	if err := os.Mkdir(repoDir, 0755); err != nil {
		t.Fatalf("mkdir %s: %v", repoDir, err)
	}

	// Initialize git repo
	if err := internalgit.Command(nil, repoDir, "init").Run(); err != nil {
		t.Fatalf("git init: %v", err)
	}
	if err := internalgit.Command(nil, repoDir, "config", "user.email", "test@test.com").Run(); err != nil {
		t.Fatalf("git config: %v", err)
	}
	if err := internalgit.Command(nil, repoDir, "config", "user.name", "Test").Run(); err != nil {
		t.Fatalf("git config: %v", err)
	}

	// Create a target directory with some content
	targetDir := filepath.Join(repoDir, "target")
	if err := os.Mkdir(targetDir, 0755); err != nil {
		t.Fatalf("mkdir %s: %v", targetDir, err)
	}
	if err := os.WriteFile(filepath.Join(targetDir, "file.txt"), []byte("content"), 0644); err != nil {
		t.Fatalf("write file: %v", err)
	}

	// Create .crush/skills directory and symlink
	skillDir := filepath.Join(repoDir, ".crush", "skills")
	if err := os.MkdirAll(skillDir, 0755); err != nil {
		t.Fatalf("mkdir %s: %v", skillDir, err)
	}
	symlink := filepath.Join(skillDir, "nano-banana-pro-openrouter")
	if err := os.Symlink("../../target", symlink); err != nil {
		t.Fatalf("symlink: %v", err)
	}

	// Add and commit the symlink
	if err := internalgit.Command(nil, repoDir, "add", ".crush/skills/nano-banana-pro-openrouter").Run(); err != nil {
		t.Fatalf("git add symlink: %v", err)
	}
	if err := internalgit.Command(nil, repoDir, "commit", "-m", "add symlink").Run(); err != nil {
		t.Fatalf("git commit: %v", err)
	}

	// Now materialize the symlink into a directory with matching contents
	if err := os.Remove(symlink); err != nil {
		t.Fatalf("remove symlink: %v", err)
	}
	if err := os.Mkdir(symlink, 0755); err != nil {
		t.Fatalf("mkdir: %v", err)
	}
	// Copy target contents into the materialized dir
	if err := os.WriteFile(filepath.Join(symlink, "file.txt"), []byte("content"), 0644); err != nil {
		t.Fatalf("write materialized file: %v", err)
	}

	// Check that the materialized symlink is not detected as dirty implementation
	dirty, err := preDispatchCheckpointDirtyPaths(repoDir)
	if err != nil {
		t.Fatalf("preDispatchCheckpointDirtyPaths: %v", err)
	}

	// The materialized symlink should appear in the dirty list
	if len(dirty) == 0 {
		t.Fatal("expected materialized symlink to show as dirty initially")
	}

	// After filtering out materialized symlinks, the list should be empty
	filtered, err := filterOutMaterializedSymlinks(repoDir, dirty)
	if err != nil {
		t.Fatalf("filterOutMaterializedSymlinks: %v", err)
	}
	if len(filtered) != 0 {
		t.Errorf("expected no blocking paths after filtering materialized symlinks, got %v", filtered)
	}
}

// TestPreClaim_RealImplementationChangesStillBlocked verifies that genuine
// uncommitted code edits are still detected as blocking changes (regression test).
func TestPreClaim_RealImplementationChangesStillBlocked(t *testing.T) {
	// Create a temporary repo with a code file
	tempDir := t.TempDir()
	repoDir := filepath.Join(tempDir, "repo")
