	}

	// The code file should appear in the dirty list
	if len(dirty) == 0 {
		t.Fatal("expected real code change to show as dirty")
	}

	// After filtering materialized symlinks, the list should still contain the code file
	filtered, err := filterOutMaterializedSymlinks(repoDir, dirty)
	if err != nil {
		t.Fatalf("filterOutMaterializedSymlinks: %v", err)
	}
	if len(filtered) == 0 {
		t.Error("expected real code changes to still be blocked after filtering materialized symlinks")
	}
	found := false
	for _, p := range filtered {
		if p == "main.go" {
			found = true
			break
		}
	}
	if !found {
		t.Errorf("expected main.go in filtered paths, got %v", filtered)
	}
}

// TestIsTrackedSymlinkMaterialized verifies the detection logic for materialized symlinks
func TestIsTrackedSymlinkMaterialized(t *testing.T) {
	tempDir := t.TempDir()
	repoDir := filepath.Join(tempDir, "repo")
	if err := os.Mkdir(repoDir, 0755); err != nil {
		t.Fatalf("mkdir: %v", repoDir)
	}

	// Initialize git
	if err := internalgit.Command(nil, repoDir, "init").Run(); err != nil {
		t.Fatalf("git init: %v", err)
	}
	if err := internalgit.Command(nil, repoDir, "config", "user.email", "test@test.com").Run(); err != nil {
		t.Fatalf("git config: %v", err)
	}
	if err := internalgit.Command(nil, repoDir, "config", "user.name", "Test").Run(); err != nil {
		t.Fatalf("git config: %v", err)
	}

	// Create target directory
	targetDir := filepath.Join(repoDir, "target")
	if err := os.Mkdir(targetDir, 0755); err != nil {
		t.Fatalf("mkdir: %v", err)
	}
	if err := os.WriteFile(filepath.Join(targetDir, "file.txt"), []byte("content"), 0644); err != nil {
		t.Fatalf("write: %v", err)
	}

	// Create symlink and commit
	symlink := filepath.Join(repoDir, "link")
	if err := os.Symlink("target", symlink); err != nil {
		t.Fatalf("symlink: %v", err)
	}
	if err := internalgit.Command(nil, repoDir, "add", "link").Run(); err != nil {
		t.Fatalf("git add: %v", err)
	}
	if err := internalgit.Command(nil, repoDir, "commit", "-m", "add link").Run(); err != nil {
		t.Fatalf("git commit: %v", err)
	}

	// Test: non-materialized symlink should return false
	isMaterialized, err := isTrackedSymlinkMaterialized(repoDir, "link")
	if err != nil {
		t.Fatalf("isTrackedSymlinkMaterialized: %v", err)
	}
	if isMaterialized {
		t.Error("symlink should not be detected as materialized when it's still a symlink")
	}

	// Materialize the symlink
	if err := os.Remove(symlink); err != nil {
		t.Fatalf("remove: %v", err)
	}
	if err := os.Mkdir(symlink, 0755); err != nil {
		t.Fatalf("mkdir: %v", err)
	}
	if err := os.WriteFile(filepath.Join(symlink, "file.txt"), []byte("content"), 0644); err != nil {
		t.Fatalf("write: %v", err)
	}

	// Test: materialized symlink with matching contents should return true
	isMaterialized, err = isTrackedSymlinkMaterialized(repoDir, "link")
	if err != nil {
		t.Fatalf("isTrackedSymlinkMaterialized: %v", err)
	}
	if !isMaterialized {
		t.Error("materialized symlink with matching contents should be detected")
	}

	// Test: materialized symlink with different contents should return false
	if err := os.WriteFile(filepath.Join(symlink, "file.txt"), []byte("different"), 0644); err != nil {
		t.Fatalf("write: %v", err)
	}
	isMaterialized, err = isTrackedSymlinkMaterialized(repoDir, "link")
	if err != nil {
		t.Fatalf("isTrackedSymlinkMaterialized: %v", err)
	}
	if isMaterialized {
		t.Error("materialized symlink with different contents should not be detected as benign")
	}
}

