// materialized into directories with matching contents. These represent
// tool-managed skill directories (e.g., .crush/skills/*, .claude/skills/*)
// that have been installed/synced externally, not genuine code changes.
// Returns the filtered set of truly blocking paths.
func filterOutMaterializedSymlinks(projectRoot string, paths []string) ([]string, error) {
	if projectRoot == "" || len(paths) == 0 {
		return paths, nil
	}
	var blocking []string
	for _, path := range paths {
		isMaterialized, err := isTrackedSymlinkMaterialized(projectRoot, path)
		if err != nil {
