// filterOutMaterializedSymlinks removes paths that are tracked symlinks
// materialized into directories with matching contents, or files within
// such materialized directories. These represent tool-managed skill directories
// (e.g., .crush/skills/*, .claude/skills/*) that have been installed/synced
// externally, not genuine code changes. Returns the filtered set of truly
// blocking paths.
func filterOutMaterializedSymlinks(projectRoot string, paths []string) ([]string, error) {
	if projectRoot == "" || len(paths) == 0 {
		return paths, nil
	}

	// Build a set of materialized symlink roots to skip
	materializedRoots := make(map[string]bool)

	var blocking []string
	for _, path := range paths {
		// Check if this path is inside a materialized symlink
		isInMaterialized := false
		for root := range materializedRoots {
			if strings.HasPrefix(path+"/", root+"/") || path == root {
				isInMaterialized = true
				break
			}
		}
		if isInMaterialized {
			continue
		}

		// Check if this path itself is a tracked symlink that's been materialized
		isMaterialized, err := isTrackedSymlinkMaterialized(projectRoot, path)
		if err != nil {
			return nil, err
		}
		if isMaterialized {
			materializedRoots[path] = true
			continue
		}

		// Check if the parent directory is a materialized symlink
		parentPath := filepath.Dir(path)
		if parentPath != "." && parentPath != path {
			isMaterialized, err := isTrackedSymlinkMaterialized(projectRoot, parentPath)
			if err != nil {
				return nil, err
			}
			if isMaterialized {
				materializedRoots[parentPath] = true
				continue
			}
		}

		blocking = append(blocking, path)
	}
	return blocking, nil
}

