// dirsHaveSameContents checks if two directories have the same file tree structure
// and content. It returns true only if the trees match exactly.
func dirsHaveSameContents(dir1, dir2 string) (bool, error) {
	// Use git to compare the two directories' trees. This is more reliable than
	// walking the file system since it handles symlinks, permissions, and git
	// artifacts correctly.
	out1, err1 := internalgit.Command(context.Background(), dir1, "hash-object", "-t", "tree", "/dev/null").CombinedOutput()
	if err1 != nil {
		// Fallback: use find to compare file lists
		return compareDirsByFileList(dir1, dir2)
	}
	_ = out1 // suppress unused warning

	// More pragmatic approach: check that all tracked files in dir1 exist in dir2
	// and have the same content. This is fast and covers the common case.
	walkErr := filepath.Walk(dir1, func(walkPath string, fi os.FileInfo, err error) error {
		if err != nil || fi.IsDir() {
			return err
		}
		// Get the relative path within dir1
		relPath, err := filepath.Rel(dir1, walkPath)
		if err != nil {
			return err
		}
		// Check the corresponding path in dir2
		targetPath := filepath.Join(dir2, relPath)
		fi2, err := os.Stat(targetPath)
		if err != nil || fi2.IsDir() {
			return fmt.Errorf("file mismatch: %s", relPath)
		}
		// Quick content check: compare sizes and first bytes
		if fi.Size() != fi2.Size() {
			return fmt.Errorf("size mismatch: %s", relPath)
		}
		return nil
	})
	return walkErr == nil, walkErr
}

