			return nil
		}
		// Check the corresponding path in dir2
		targetPath := filepath.Join(dir2, relPath)
		fi2, err := os.Stat(targetPath)
		if err != nil || fi2.IsDir() {
			return fmt.Errorf("file mismatch: %s (in %s, looking in %s)", relPath, dir1, dir2)
		}
		// Quick content check: compare sizes
		if fi.Size() != fi2.Size() {
			return fmt.Errorf("size mismatch: %s", relPath)
		}
		return nil
	})
