// isTrackedSymlinkMaterialized reports whether a path is a tracked symlink
// that has been materialized into a directory with matching contents.
// Returns false if the path is not tracked, not a symlink, or the
// directory contents don't match the symlink target.
func isTrackedSymlinkMaterialized(projectRoot, path string) (bool, error) {
	// Check if the path is tracked as a symlink in git.
	out, err := internalgit.Command(context.Background(), projectRoot, "ls-files", "-s", "--", path).CombinedOutput()
	if err != nil || len(bytes.TrimSpace(out)) == 0 {
		return false, nil // Path not tracked or not a symlink
	}

	// Parse git ls-files -s output: "[mode] [object] [stage] [file]"
	parts := bytes.Fields(bytes.TrimSpace(out))
	if len(parts) < 2 {
		return false, nil
	}

	// Check if mode is 120000 (symlink)
	mode := string(parts[0])
	if mode != "120000" {
		return false, nil // Not a symlink
	}

	// Check if a directory exists at this path
	fsPath := filepath.Join(projectRoot, path)
	fi, err := os.Stat(fsPath)
	if err != nil || !fi.IsDir() {
		return false, nil // File doesn't exist or is not a directory
	}

	// Get the symlink target from git
	linkOut, err := internalgit.Command(context.Background(), projectRoot, "cat-file", "-p", "HEAD:"+filepath.ToSlash(path)).CombinedOutput()
	if err != nil {
		// Failed to read symlink content from git
		return false, nil
	}
	symTarget := string(bytes.TrimSpace(linkOut))

	// Resolve the symlink target relative to the path
	baseDir := filepath.Dir(fsPath)
	resolvedPath := filepath.Join(baseDir, symTarget)
	resolvedPath = filepath.Clean(resolvedPath)

	// Check if the resolved path exists and matches the working tree directory
	fi2, err := os.Stat(resolvedPath)
	if err != nil || !fi2.IsDir() {
		return false, nil // Target doesn't exist or is not a directory
	}

	// Verify the materialized directory has the same contents as the target
	return dirsHaveSameContents(fsPath, resolvedPath)
}

